  // 1. Limpeza do valor padrão BR (Ex: "96.996,55")
  // .replace(/\./g, '') -> Remove todos os pontos de milhar (vira "96996,55")
  // .replace(',', '.')  -> Troca a vírgula por ponto (vira "96996.55")
  const valorTexto = dados['VALOR SOLICITADO'] || "0";
  const valorLimpo = valorTexto.toString().replace(/\./g, '').replace(',', '.');
  const valor = parseFloat(valorLimpo);

  const tipo = dados['TIPO'];

  // 2. Lógica RPV: Entre 20k e 60k
  if (tipo === 'RPV' && valor >= 20000 && valor <= 60000) {
    return true;
  }

  // 3. Lógica PRC: Acima ou igual a 50k
  if (tipo === 'PRC' && valor >= 50000) {
    return true;
  }

  return false;
});

