/* =========================
   UTILITÁRIOS
========================= */
const normalizeCPF = (v) => v.replace(/\D/g, '');
const isCPF = (v) => /^\d{11}$/.test(v);

/* =========================
   Nº DA REQUISIÇÃO
   Ex: Nº:0003265.2025.8.06682
========================= */
let numeroRequisicao = null;

const requisicaoRegexes = [
  /N[ºo]\s*[:\-]?\s*([\d.]+)/i,
  /REQUISI[CÇ][AÃ]O[\s\S]{0,40}?([\d.]{6,})/i
];

for (const r of requisicaoRegexes) {
  const m = text.match(r);
  if (m) {
    numeroRequisicao = m[1];
    break;
  }
}

/* =========================
   BENEFICIÁRIO (FORTE)
   JOSE ... 38597683287 Não 01/02/2025
========================= */
let nomeBeneficiario = null;
let cpfBeneficiario = null;

const strongRegex =
  /([A-ZÁÉÍÓÚÂÊÔÃÕÇ\s]{5,})\s+(\d{11})\s+(?:Não|Sim)\s+\d{2}\/\d{2}\/\d{4}/;

const strongMatch = text.match(strongRegex);

if (strongMatch) {
  nomeBeneficiario = strongMatch[1].trim();
  cpfBeneficiario = strongMatch[2];
} else {
  /* =========================
     CONTEXTO SEMÂNTICO
  ========================= */
  const contextRegex =
    /(BENEFICI[AÁ]RIO|REQUERENTE|CREDOR)[\s\S]{0,120}?([A-ZÁÉÍÓÚÂÊÔÃÕÇ\s]{5,})[\s\S]{0,40}?(\d{3}\.?\d{3}\.?\d{3}-?\d{2})/i;

  const contextMatch = text.match(contextRegex);

  if (contextMatch) {
    nomeBeneficiario = contextMatch[2].trim();
    cpfBeneficiario = normalizeCPF(contextMatch[3]);
  } else {
    /* =========================
       FALLBACK CPF LIMPO
    ========================= */
    const cpfCandidates = [...text.matchAll(/\b\d{3}\.?\d{3}\.?\d{3}-?\d{2}\b/g)]
      .map(m => normalizeCPF(m[0]))
      .filter(isCPF);

    if (cpfCandidates.length) {
      cpfBeneficiario = cpfCandidates[0];
    }
  }
}

/* =========================
   OUTPUT FIXO
========================= */
return [
  {
    numeroRequisicao,
    nomeBeneficiario,
    cpfBeneficiario
  }
];

