const rawText = $json.text || '';

const text = rawText
  .replace(/\u00A0/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

/* =========================
   1. PROCESSO (CNJ)
   PRIORIDADE SEMÂNTICA
========================= */

let numeroProcesso = null;

/**
 * Linha explícita "Processo:"
 * Aceita CNJ cru (20 dígitos)
 * ou CNJ mascarado
 */
const processoLinhaRegex =
  /Processo\s*:\s*(\d{20}|\d{7}-\d{2}\.\d{4}\.\d\.\d{2}\.\d{4})/i;

const processoLinhaMatch = text.match(processoLinhaRegex);

if (processoLinhaMatch) {
  const p = processoLinhaMatch[1];

  // CNJ cru → mascara
  if (/^\d{20}$/.test(p)) {
    numeroProcesso =
      `${p.slice(0,7)}-${p.slice(7,9)}.` +
      `${p.slice(9,13)}.${p.slice(13,14)}.` +
      `${p.slice(14,16)}.${p.slice(16,20)}`;
  } else {
    numeroProcesso = p;
  }
} else {
  /**
   * Fallback — CNJ mascarado solto
   * (usado só se não existir "Processo:")
   */
  const cnjFallback =
    text.match(/\d{7}-\d{2}\.\d{4}\.\d\.\d{2}\.\d{4}/);

  if (cnjFallback) {
    numeroProcesso = cnjFallback[0];
  }
}

/* =========================
   2. OFÍCIO REQUISITÓRIO
   (multi-tribunal)
========================= */

const oficioPatterns = [
  /OF[IÍ]CIO\s+REQUISIT[ÓO]RIO\s*(?:n[ºo]\s*)?([\d.]+)/i,
  /REQUISI[CÇ][AÃ]O(?:\s+DE\s+PAGAMENTO)?\s*(?:n[ºo]\s*)?([\d.]+)/i,
  /\b(PRC|RPV)\b\s*(?:n[ºo]\s*)?([\d.]{6,})/i,
  /N[ºo]\s*[:\-]?\s*([\d.]{6,})/i
];

let oficio = null;

for (const regex of oficioPatterns) {
  const match = text.match(regex);
  if (match) {
    oficio = match[2] || match[1];
    break;
  }
}

/* =========================
   3. FALLBACK BRUTO
========================= */
if (!oficio) {
  const brute = text.match(/\b\d{8,}\b/);
  if (brute) oficio = brute[0];
}

/* =========================
   4. NORMALIZAÇÃO
========================= */
if (oficio) {
  oficio = oficio.replace(/[^\d.]/g, '');
}

/* =========================
   SAÍDA (n8n)
========================= */
return [
  {
    json: {
      numeroProcesso,
      oficioRequisitorio: oficio
    }
  }
];
